Feature 4 Code: Seasonality
matrix[T, K] C_fourier;
matrix[T, K] S_fourier;

for (t in 1:T) {
  for (k in 1:K) {
    real omega = 2 * pi() * k / P;
    C_fourier[t, k] = cos(omega * t);
    S_fourier[t, k] = sin(omega * t);
  }
}

season[c] = rep_vector(0, T);
if (K &gt; 0) {
  season[c] = C_fourier * a_cos[c] + S_fourier * b_sin[c];
}
