Feature 5 Code: AR(1) Correlation
vector&lt;lower=-1, upper=1&gt;[C] rho;
vector&lt;lower=0&gt;[C] sigma_z;
array[C] vector[T] eps_z;

z[c][1] = eps_z[c][1] * (sigma_z[c] / sqrt(1 - square(rho[c])));
for (t in 2:T) {
  z[c][t] = rho[c] * z[c][t - 1] + sigma_z[c] * eps_z[c][t];
}
